                ops.push_back(c);
            }
        }
        if (!current_number.empty()) {
            numbers.push_back(stoi(current_number));
        }

        int i = 0;
        while (i < ops.size()) {
            if (ops[i] == '*' || ops[i] == '/') {
                int a = numbers[i];
                int b = numbers[i + 1];
                int res;
                if (ops[i] == '*') {
                    res = a * b;
                } else {
                    res = a / b;
                }
                numbers.erase(numbers.begin() + i + 1);
                numbers[i] = res;
                ops.erase(ops.begin() + i);
            } else {
                i++;
